package com.genc.patient.service;

import com.genc.patient.model.Doctor;
import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;

@FeignClient("doctor")
public interface DoctorClient {
    @GetMapping("/doctor/id/{id}")
    Doctor getDoctor(@PathVariable("id") Long id);
}

package com.genc.patient.model;

import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import lombok.AllArgsConstructor;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.util.List;

@Entity
@Getter
@Setter
@AllArgsConstructor
@NoArgsConstructor
public class Patient {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    private String name;

    transient private Doctor doctor;
}

package com.genc.patient.model;

import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import lombok.AllArgsConstructor;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

@Entity
@Getter
@Setter
@AllArgsConstructor
@NoArgsConstructor
public class Patient {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    private String name;
    private Long doctorId;

    transient private Doctor doctor;
}

package com.genc.patient.service;

import com.genc.patient.model.Patient;
import com.genc.patient.repository.PatientRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class PatientService {
    @Autowired
    private PatientRepository repository;

    @Autowired
    private DoctorClient doctorClient;

    public Patient add(Patient patient) {
        return repository.save(patient);
    }

    public List<Patient> getAll() {
        List<Patient> patients = repository.findAll();
        patients.stream().map(patient -> {
            patient.setDoctor(doctorClient.getDoctor(patient.getId()));
            return patient;
        });
        return patients;
    }

    public Patient getById(Long id) {
        Patient patient = repository.findById(id).orElseThrow(() -> new RuntimeException("Patient Not Found"));
        patient.setDoctor(doctorClient.getDoctor(patient.getId()));
        return patient;
    }

}

package com.genc.patient.service;

import com.genc.patient.model.Patient;
import com.genc.patient.repository.PatientRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.stream.Collectors;

@Service
public class PatientService {
    @Autowired
    private PatientRepository repository;

    @Autowired
    private DoctorClient doctorClient;

    public Patient add(Patient patient) {
        return repository.save(patient);
    }

    public List<Patient> getAll() {
        List<Patient> patients = repository.findAll();
        patients = patients.stream().map(patient -> {
            patient.setDoctor(doctorClient.getDoctor(patient.getDoctorId()));
            return patient;
        }).collect(Collectors.toList());
        return patients;
    }

    public Patient getById(Long id) {
        Patient patient = repository.findById(id).orElseThrow(() -> new RuntimeException("Patient Not Found"));
        patient.setDoctor(doctorClient.getDoctor(patient.getDoctorId()));
        return patient;
    }

}
